restoration[tree_, root_] := 
 Module[{r, p, ta, n}, 
 	ta = treeArray[tree, root]; 
  	n = Length[tree] + 1; r[T_, k_, k_] := 1 /; leafQ[T, k];
  	p[T_, k_] := 2 /; leafQ[T, k];
  	r[T_, k_, k_] := 
   	LCM @@ Map[p[T, #]&, children[T, k]] /; Not[leafQ[T, k]];
  	p[T_, k_] := 
        p[T, k] = (2 + Length[children[T, k]]) r[T, k, k] - 
                     Total[Map[r[T, k, #]&, children[T, k]]];
  	r[T_, k_, j_] := 
   	r[T, k, j] = 
    		Module[{i}, 
			i = (Select[children[T, k], 
			MemberQ[Join[{#}, descendants[T, #]], j]&]) // First; 
			r[T, k, k] r[T, i, j]/p[T, i]]; 
  	Map[{#, r[ta, root, #]}&, Range[n]] ]

